<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { CheckCircle2, KeyRound, LoaderCircle, MailCheck, Send, ShieldAlert, ShieldCheck } from '@lucide/vue'
import { api, readableError } from '../api'
import AppShell from '../components/AppShell.vue'

defineProps<{ theme: 'light' | 'dark' }>(); const emit = defineEmits<{ toggleTheme: [] }>()
const loading = ref(true); const saving = ref(false); const testing = ref(false); const error = ref(''); const success = ref(''); const passwordConfigured = ref(false)
const form = reactive({ host: '', port: 587, security: 'starttls', from_email: '', from_name: 'WOLT', public_base_url: window.location.origin, username: '', password: '', enabled: true, recipient: '' })
async function load() { try { const value = await api.smtp(); if (value.configured) Object.assign(form, { host: value.host, port: value.port, security: value.security, from_email: value.from_email, from_name: value.from_name, public_base_url: value.public_base_url, username: value.username, password: '', enabled: value.enabled }); passwordConfigured.value = Boolean(value.password_configured) } catch (reason) { error.value = readableError(reason) } finally { loading.value = false } }
function payload() { return { host: form.host, port: Number(form.port), security: form.security, from_email: form.from_email, from_name: form.from_name, public_base_url: form.public_base_url, username: form.username, password: form.password, enabled: form.enabled } }
async function test() { error.value = ''; success.value = ''; if (!form.recipient) { error.value = 'Enter a test recipient.'; return } testing.value = true; try { await api.testSmtp({ ...payload(), recipient: form.recipient }); success.value = `Test email delivered to ${form.recipient}.` } catch (reason) { error.value = readableError(reason) } finally { testing.value = false } }
async function save() { saving.value = true; error.value = ''; success.value = ''; try { const value = await api.saveSmtp(payload()); passwordConfigured.value = Boolean(value.password_configured); form.password = ''; success.value = 'SMTP settings saved with encrypted credentials.' } catch (reason) { error.value = readableError(reason) } finally { saving.value = false } }
onMounted(load)
</script>

<template><AppShell :theme="theme" @toggle-theme="emit('toggleTheme')"><section class="page-heading"><div><p class="eyebrow">ADMINISTRATION / EMAIL</p><h1>SMTP delivery</h1><p>Configure invitation, password-reset, and security notification delivery.</p></div></section><p v-if="error" class="form-error page-error" role="alert">{{ error }}</p><p v-if="success" class="form-success page-message"><CheckCircle2 :size="15" /> {{ success }}</p><section v-if="loading" class="panel loading-panel"><LoaderCircle class="spin" /> Loading SMTP settings…</section><form v-else class="settings-layout smtp-layout" @submit.prevent="save"><section class="panel settings-card"><header><MailCheck :size="20" /><div><h2>Mail server</h2><p>STARTTLS is recommended for port 587. TLS commonly uses port 465.</p></div></header><div class="operations-form"><div class="form-row equal"><label>SMTP host<input v-model.trim="form.host" required placeholder="smtp.example.com" /></label><label>Port<input v-model.number="form.port" required type="number" min="1" max="65535" /></label></div><label>Transport security<select v-model="form.security"><option value="starttls">STARTTLS</option><option value="tls">Implicit TLS</option><option value="none">None — trusted internal relay</option></select></label><div v-if="form.security === 'none'" class="retention-note roadmap-note"><ShieldAlert :size="17" /><p>No TLS or certificate validation will be used, including on port 587. Use only for an IP-restricted internal relay on a trusted network. Leave credentials blank for source-IP relay; configured authentication must still use a mechanism supported by WOLT.</p></div><div class="form-row equal"><label>Username<input v-model.trim="form.username" autocomplete="off" /></label><label>Password<input v-model="form.password" type="password" autocomplete="new-password" :placeholder="passwordConfigured ? 'Leave blank to keep current secret' : 'SMTP password'" /><small v-if="passwordConfigured"><ShieldCheck :size="12" /> Encrypted password configured</small></label></div><div class="form-row equal"><label>From email<input v-model.trim="form.from_email" required type="email" /></label><label>From name<input v-model.trim="form.from_name" required /></label></div><label>Public WOLT URL<input v-model.trim="form.public_base_url" required type="url" placeholder="https://wolt.example.com" /><small>Invitation and reset links use this externally reachable URL.</small></label><label class="toggle-label"><input v-model="form.enabled" type="checkbox" /><span>{{ form.enabled ? 'Email delivery enabled' : 'Email delivery disabled' }}</span></label><footer><button class="primary-button" :disabled="saving" type="submit"><LoaderCircle v-if="saving" class="spin" :size="15" /><KeyRound v-else :size="15" /> Save encrypted settings</button></footer></div></section><aside class="panel settings-card"><header><Send :size="20" /><div><h2>Connection test</h2><p>Sends a real message using the values currently in this form.</p></div></header><div class="operations-form"><label>Test recipient<input v-model.trim="form.recipient" type="email" placeholder="admin@example.com" /></label><button class="secondary-button button-link" :disabled="testing" type="button" @click="test"><LoaderCircle v-if="testing" class="spin" :size="15" /><Send v-else :size="15" /> Send test email</button><div class="retention-note"><ShieldCheck :size="17" /><p>SMTP credentials are encrypted with <code>WOLT_MASTER_KEY</code>, never returned by the API, and excluded from audit records.</p></div><div class="retention-note"><ShieldCheck :size="17" /><p>Private corporate CA certificates are configured by mounting a PEM CA bundle and setting <code>WOLT_SMTP_CA_FILE</code>. WOLT never disables certificate verification for TLS modes.</p></div></div></aside></form></AppShell></template>
